import sys 
from typing import List 

class ListNode: 
    def __init__(self, x): 
        self.val = x 
        self.next = None 

class Solution: 
    def addAtHead(self, head: ListNode, val: int) -> ListNode: 
        new_node = ListNode(val) 
        new_node.next = head 
        return new_node

def read_array(stdin_stream): 
    return [int(x.strip()) for x in stdin_stream.split('\n')] 

if __name__ == '__main__':
def main():
        stdin_stream = sys.stdin.read()
        stdin_list = read_array(stdin_stream)
        head = None
        for x in stdin_list[1:]:
            new_node = ListNode(x)
            new_node.next = head
            head = new_node
        solution = Solution()
        result = solution.addAtHead(head, stdin_list[0])
        sys.stdout.write(' '.join(str(x.val) for x in result))
main()
